mapper.select:
SELECT product_name                      AS productName,
       COALESCE(SUM(sum_quantity), 0)    AS totalQuantity,
       COALESCE(SUM(sum_amount), 0)      AS totalAmount,
       COALESCE(SUM(sum_profit), 0)      AS totalProfit
FROM stat_daily_product_sales
WHERE enterprise_id = #{enterpriseId}
  AND stat_date >= #{startDate}
  AND stat_date <= #{endDate}
GROUP BY product_name
ORDER BY totalAmount DESC
LIMIT #{limit}
